import java.util.ArrayList;import java.util.List;import java.util.Map;import java.util.TreeMap;
final class BulkheadPattern{static final class PatternException extends RuntimeException{private final String code;PatternException(String c){super(c);code=c;}String code(){return code;}}@SuppressWarnings("unchecked")static Object evaluate(Map<String,Object>input){Map<String,Integer>capacity=new TreeMap<>(),used=new TreeMap<>();((Map<String,Object>)input.get("capacities")).forEach((k,v)->{capacity.put(k,((Number)v).intValue());used.put(k,0);});List<String>out=new ArrayList<>();for(Map<String,Object>action:(List<Map<String,Object>>)input.getOrDefault("actions",List.of())){String pool=String.valueOf(action.get("pool"));if(!capacity.containsKey(pool))throw new PatternException("unknown_pool");switch(String.valueOf(action.get("op"))){case"acquire"->{if(used.get(pool)>=capacity.get(pool))out.add("rejected:"+pool);else{used.put(pool,used.get(pool)+1);out.add("accepted:"+pool);}}case"release"->{if(used.get(pool)<=0)throw new PatternException("over_release");used.put(pool,used.get(pool)-1);out.add("released:"+pool);}default->throw new PatternException("unsupported_action");}}return Map.of("decisions",out,"used",used);}}
